definition.script:
pipeline {
    agent any
    environment {
        DUMMY_APP_URL = 'http://localhost:3099'
        SHIPGATE_API  = 'http://localhost:4000'
        E2E_DIR       = '/Users/umarsaeed/shipgate/tests/e2e'
    }
    stages {
        stage('Setup') {
            steps {
                script {
                    env.PATH = "/opt/homebrew/bin:/opt/homebrew/opt/node/bin:/usr/local/bin:${env.PATH}"
                }
                sh 'node --version'
                sh 'npm --version'
            }
        }
        stage('Verify Services') {
            steps {
                sh 'curl -sf http://localhost:3099/login > /dev/null'
                sh 'curl -sf http://localhost:4000/health > /dev/null'
                echo 'Dummy App and Shipgate API are running'
            }
        }
        stage('Install Dependencies') {
            steps {
                dir("${env.E2E_DIR}") {
                    sh 'npm install'
                }
            }
        }
        stage('Clean Previous Results') {
            steps {
                dir("${env.E2E_DIR}") {
                    sh 'rm -rf allure-results allure-report || true'
                }
                sh 'rm -rf allure-results allure-report || true'
            }
        }
        stage('Seed Shipgate') {
            steps {
                dir("${env.E2E_DIR}") {
                    script {
                        def output = sh(script: 'node seed-shipgate.js', returnStdout: true).trim()
                        echo output
                        def appMatch = output =~ /APP_ID="([^"]+)"/
                        def suiteMatch = output =~ /SUITE_ID="([^"]+)"/
                        if (appMatch.find()) { env.APP_ID = appMatch.group(1) }
                        if (suiteMatch.find()) { env.SUITE_ID = suiteMatch.group(1) }
                        echo "Using APP_ID=${env.APP_ID} SUITE_ID=${env.SUITE_ID}"
                    }
                }
            }
        }
        stage('Run Smoke Tests') {
            steps {
                dir("${env.E2E_DIR}") {
                    sh "APP_ID=${env.APP_ID} SUITE_ID=${env.SUITE_ID} node report-to-shipgate.js || true"
                }
            }
        }
        stage('Collect Allure Results') {
            steps {
                sh "cp -r ${env.E2E_DIR}/allure-results . || true"
                sh 'ls allure-results/ | wc -l | xargs -I{} echo "Copied {} allure result files to workspace"'
            }
        }
        stage('Generate Allure Report') {
            steps {
                sh 'allure generate allure-results --clean -o allure-report'
                sh "rm -rf ${env.E2E_DIR}/allure-report || true"
                sh "cp -r allure-report ${env.E2E_DIR}/allure-report"
                echo 'Allure report generated and copied'
            }
        }
    }
    post {
        always {
            script {
                step([$class: 'ru.yandex.qatools.allure.jenkins.AllureReportPublisher', results: [[path: 'allure-results']], reportBuildPolicy: 'ALWAYS'])
            }
            echo "Pipeline complete."
            echo "Allure Report (Jenkins): http://localhost:9090/job/smoke-test-pipeline/${env.BUILD_NUMBER}/allure/"
            echo "Allure Report (Static): http://localhost:9095"
            echo "Shipgate Runs: http://localhost:3000/runs"
        }
        success {
            echo 'BUILD SUCCESS - Smoke tests executed with Allure reporting'
        }
        failure {
            echo 'BUILD FAILED'
        }
    }
}
